#include<iostream>#include<vector>using namespace std;void solve(){    int n;        cin>>n;        vector<int>a(n);        for(int i=0;i<n;i++){            cin>>a[i];         }        int l=0;        int r= n-1;        int curr_min=1;        int curr_max=n;        while(l<=r){            if(a[l]==curr_min){                l++;                curr_min++;            }            else if(a[l]==curr_max){                l++;                curr_max--;            }            else if(a[r]==curr_min){                r--;                curr_min++;            }            else if(a[r]==curr_max){                r--;                curr_max--;            }            else{                cout<<l + 1<<" "<<r + 1<<"\n";                return;            }        }        cout<<-1<<"\n";}int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        solve();    }}